{
  "executive_summary": "A lightweight ML serving architecture for real-time delivery time prediction, built around a pre-computed feature store, a versioned model registry with blue-green deployment, and an offline training pipeline. The design prioritizes sub-100ms P99 latency at the serving layer, safe weekly model rollouts with instant rollback, and a clean separation between the training and serving bounded contexts. Sized for a 4-person team — no Kubernetes, no feature platform, no overengineering.",

  "architecture": {
    "components": [
      {
        "name": "Prediction API",
        "responsibility": "Serves real-time delivery time predictions. Loads the active model version into memory, assembles features, runs inference, and returns the estimate. Stateless — scales horizontally behind a load balancer.",
        "boundaries": "Owns only the inference path. Does not train models, does not write to the feature store. Reads features and model artifacts."
      },
      {
        "name": "Feature Store",
        "responsibility": "Pre-computes and serves features for both training and inference. Splits into an offline store (batch features: zone historical averages, courier reliability scores) and an online store (real-time features: current courier load, live weather). The online store is a Redis cluster keyed by zone/courier/time-bucket.",
        "boundaries": "Owns feature computation logic and storage. Consumers (Prediction API, Training Pipeline) read from it but never compute features themselves — single source of truth for feature definitions."
      },
      {
        "name": "Model Registry",
        "responsibility": "Versioned storage for trained model artifacts, metadata (training metrics, dataset hash, hyperparameters), and deployment state (which version is 'active', which is 'canary', which is 'rollback-target'). Implemented as an S3 bucket with a metadata table in PostgreSQL.",
        "boundaries": "Owns model lifecycle state. Training Pipeline writes new versions here. Prediction API reads the active version. Deployment Controller reads/writes deployment state."
      },
      {
        "name": "Training Pipeline",
        "responsibility": "Weekly batch job that pulls delivery outcome data, joins with historical features from the offline feature store, trains a new model (gradient-boosted trees via LightGBM/XGBoost), evaluates against validation set and shadow traffic, and registers the new version in the Model Registry.",
        "boundaries": "Owns model training and offline evaluation. Runs in an isolated compute environment (e.g., a scheduled ECS task or a simple VM). Has no access to production serving infrastructure."
      },
      {
        "name": "Deployment Controller",
        "responsibility": "Manages model rollout: promotes a new model version from 'candidate' to 'canary' (shadow or small traffic %), monitors prediction quality metrics, auto-promotes to 'active' or auto-rolls back. Exposes a CLI/API for manual rollback.",
        "boundaries": "Owns deployment decisions. Reads metrics from the Monitoring system, writes deployment state to the Model Registry. Does not train or serve — only orchestrates transitions."
      },
      {
        "name": "Delivery Outcome Collector",
        "responsibility": "Captures actual delivery times after order completion. Joins predicted vs actual for model evaluation and retraining data. Writes to a delivery_outcomes table in the data warehouse.",
        "boundaries": "Owns ground truth data collection. Downstream of the order fulfillment system. Upstream of the Training Pipeline."
      },
      {
        "name": "Monitoring & Alerting",
        "responsibility": "Tracks prediction latency (P50/P95/P99), prediction distribution drift, prediction error vs actuals (MAE, MAPE), feature freshness, and model version health. Feeds the Deployment Controller's rollback decisions.",
        "boundaries": "Read-only observation layer. Consumes logs/metrics from Prediction API and Delivery Outcome Collector."
      }
    ],
    "interfaces": [
      {
        "from": "Checkout Service",
        "to": "Prediction API",
        "contract": "POST /v1/predict {order_weight_kg, distance_km, zone_id, pickup_time_utc} → {estimated_minutes, confidence_interval, model_version}. Timeout budget: 80ms client-side.",
        "coupling_type": "synchronous request-response (tight latency coupling, loose data coupling)"
      },
      {
        "from": "Prediction API",
        "to": "Feature Store (Online)",
        "contract": "GET by composite key (zone_id, time_bucket, courier_id) → {weather_code, courier_current_load, zone_avg_delivery_min, zone_congestion_score}. Must respond in <10ms.",
        "coupling_type": "synchronous read from Redis (tight latency coupling)"
      },
      {
        "from": "Prediction API",
        "to": "Model Registry",
        "contract": "On startup and on SIGHUP/config change: pull active model artifact (serialized LightGBM binary). Model is cached in-process memory — no per-request I/O to the registry.",
        "coupling_type": "async pull on deploy/reload (loose coupling)"
      },
      {
        "from": "Training Pipeline",
        "to": "Feature Store (Offline)",
        "contract": "SQL/Parquet read of historical feature-label pairs for training window (rolling 90 days).",
        "coupling_type": "batch read (loose coupling)"
      },
      {
        "from": "Training Pipeline",
        "to": "Model Registry",
        "contract": "PUT new model version with artifact + metadata (metrics, dataset_hash, feature_schema_version).",
        "coupling_type": "async write (loose coupling)"
      },
      {
        "from": "Deployment Controller",
        "to": "Model Registry",
        "contract": "Read candidate versions, write deployment state transitions (candidate → canary → active | rolled_back).",
        "coupling_type": "async state machine (loose coupling)"
      },
      {
        "from": "Deployment Controller",
        "to": "Prediction API",
        "contract": "Signals model reload via config update (e.g., update a 'active_model_version' key in Redis/config, Prediction API polls or watches). No direct RPC.",
        "coupling_type": "indirect signaling (very loose coupling)"
      },
      {
        "from": "Delivery Outcome Collector",
        "to": "Training Pipeline",
        "contract": "Writes to delivery_outcomes table (order_id, predicted_minutes, actual_minutes, features_snapshot). Training Pipeline reads this as training labels.",
        "coupling_type": "shared data store (moderate coupling, acceptable for batch)"
      }
    ],
    "data_flow": "REQUEST PATH: Checkout Service → Prediction API → [Feature Store (Redis) for real-time features] → in-memory model inference → response. Total budget: <100ms P99, broken down as: network overhead ~5ms, feature fetch ~10ms, inference ~5ms, serialization ~2ms, leaving ~78ms headroom. TRAINING PATH: Delivery Outcome Collector writes actuals to warehouse → Training Pipeline joins outcomes with offline features → trains model → registers in Model Registry → Deployment Controller promotes through canary → Prediction API reloads model. FEEDBACK LOOP: Prediction API logs (prediction, features, model_version) to async log → Delivery Outcome Collector joins with actuals → closes the loop for monitoring and retraining.",
    "patterns_used": [
      {
        "pattern": "Feature Store (dual online/offline)",
        "rationale": "Eliminates training-serving skew — the #1 silent killer in ML systems. Both training and inference use the same feature definitions. Online store (Redis) gives sub-10ms reads for serving. Offline store (Parquet/warehouse) gives bulk reads for training."
      },
      {
        "pattern": "Model Registry with immutable versioning",
        "rationale": "Every trained model is an immutable, versioned artifact. Enables instant rollback by flipping 'active_version' pointer rather than retraining. Critical for the business requirement of safe weekly deployments."
      },
      {
        "pattern": "Blue-Green Model Deployment (via canary)",
        "rationale": "New models are deployed as canary (shadow predictions logged but not returned, or small traffic percentage) before full promotion. Prevents bad models from impacting all users. Deployment Controller automates the promotion/rollback decision based on error metrics."
      },
      {
        "pattern": "In-process model loading (no model server)",
        "rationale": "For a team of 4, running a separate model serving infrastructure (TF Serving, Triton) is overhead. LightGBM/XGBoost models are small (<100MB) and fast. Loading them directly into the API process eliminates a network hop and halves latency. If the team later needs GPU inference or multi-framework support, they can introduce a model server then."
      },
      {
        "pattern": "Async logging with synchronous serving",
        "rationale": "Prediction logs (for monitoring and retraining) are written asynchronously to avoid adding latency to the critical path. The serving path is purely synchronous and deterministic."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Prediction Serving",
        "classification": "core",
        "aggregates": ["PredictionRequest (value object: order details → features → prediction)", "ModelInstance (entity: loaded model with version, feature schema, inference method)"]
      },
      {
        "name": "Model Lifecycle",
        "classification": "core",
        "aggregates": ["ModelVersion (entity: artifact, metadata, metrics, deployment state)", "DeploymentState (value object: candidate | canary | active | rolled_back)"]
      },
      {
        "name": "Feature Engineering",
        "classification": "supporting",
        "aggregates": ["FeatureDefinition (entity: name, computation logic, freshness SLA)", "FeatureValue (value object: feature_key → value, computed_at)"]
      },
      {
        "name": "Training",
        "classification": "supporting",
        "aggregates": ["TrainingRun (entity: dataset version, hyperparameters, metrics, output model version)", "TrainingDataset (value object: time window, feature set, label join)"]
      },
      {
        "name": "Delivery Outcomes",
        "classification": "generic",
        "aggregates": ["DeliveryOutcome (entity: order_id, predicted_time, actual_time, timestamps)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Feature Engineering",
        "downstream": "Prediction Serving",
        "relationship": "Open Host Service — Feature Store exposes a stable read API. Prediction Serving consumes features without knowing how they're computed."
      },
      {
        "upstream": "Model Lifecycle",
        "downstream": "Prediction Serving",
        "relationship": "Customer-Supplier — Model Lifecycle (supplier) publishes model artifacts and version metadata. Prediction Serving (customer) loads what it's told to load."
      },
      {
        "upstream": "Feature Engineering",
        "downstream": "Training",
        "relationship": "Shared Kernel — Both contexts share feature definitions to prevent training-serving skew. This is intentional tight coupling."
      },
      {
        "upstream": "Delivery Outcomes",
        "downstream": "Training",
        "relationship": "Conformist — Training conforms to whatever schema Delivery Outcomes produces. No need for an ACL given the simple tabular format."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "LightGBM/XGBoost (gradient-boosted trees) over deep learning",
      "gains": "Sub-5ms inference without GPU. Small model artifacts (<100MB). Interpretable feature importances for debugging. Proven excellent on tabular data with the feature set described (weight, distance, zone, time, weather, load).",
      "sacrifices": "Cannot easily incorporate unstructured inputs (images, free text) if needed later. May underperform deep learning if feature interactions become extremely complex.",
      "alternatives_considered": ["Deep neural network (PyTorch/TensorFlow) — rejected: requires GPU serving infra, 10-50x slower inference, overkill for tabular features, team of 4 cannot maintain GPU fleet", "Linear regression — rejected: too simple, cannot capture non-linear interactions between zone, weather, and time", "Pre-computed lookup table — rejected: too coarse, cannot handle continuous features like distance and weight"]
    },
    {
      "decision": "In-process model loading over dedicated model server (TF Serving, Triton, Seldon)",
      "gains": "Eliminates network hop (~5-15ms saved). No additional infrastructure to operate. Simple deployment — model is a file loaded at startup.",
      "sacrifices": "Cannot serve multiple model frameworks simultaneously. Model reload requires process restart or hot-reload logic. No built-in A/B testing at the serving layer.",
      "alternatives_considered": ["TF Serving — rejected: designed for TensorFlow, team uses tree models", "Triton Inference Server — rejected: powerful but massive operational overhead for a 4-person team", "Seldon Core — rejected: requires Kubernetes, adds complexity"]
    },
    {
      "decision": "Redis for online feature store over a managed feature platform (Feast, Tecton, SageMaker Feature Store)",
      "gains": "Sub-millisecond reads. Team already likely knows Redis. No vendor lock-in. Simple to operate.",
      "sacrifices": "Manual feature ingestion pipelines. No built-in feature versioning or lineage. Team must build their own feature freshness monitoring.",
      "alternatives_considered": ["Feast — considered viable for later adoption, but adds operational complexity the team doesn't need yet", "Tecton — rejected: managed service cost, vendor lock-in, overkill at this scale", "DynamoDB — viable alternative, slightly higher latency than Redis but fully managed"]
    },
    {
      "decision": "Weekly batch retraining over online/continuous learning",
      "gains": "Simpler pipeline. Deterministic training. Easy to validate before deploy. Matches the business requirement.",
      "sacrifices": "Model cannot adapt to sudden distribution shifts (e.g., a snowstorm) until next training cycle.",
      "alternatives_considered": ["Online learning — rejected: much harder to debug, validate, and roll back. 4-person team cannot maintain this safely", "Daily retraining — viable future evolution if weekly proves too stale"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Model algorithm",
      "evolution_path": "The in-process serving pattern works with any model that can be serialized and loaded into Python/C++. Swapping LightGBM for XGBoost, CatBoost, or even a small neural net requires only changing the Training Pipeline and the model loading code in the Prediction API. No infrastructure changes."
    },
    {
      "area": "Feature additions",
      "evolution_path": "Adding a new feature (e.g., traffic data, holiday flag) requires: 1) add computation to Feature Store, 2) add to training dataset, 3) retrain, 4) deploy new model version. The versioned model + feature schema in the registry ensures old models aren't served with new features."
    },
    {
      "area": "Serving infrastructure",
      "evolution_path": "If latency requirements tighten or model complexity grows, the in-process model can be replaced with a sidecar model server or a dedicated inference service. The Prediction API's interface to the Checkout Service doesn't change."
    },
    {
      "area": "Retraining frequency",
      "evolution_path": "The Training Pipeline is a scheduled job. Changing from weekly to daily is a config change. The Model Registry and Deployment Controller already handle arbitrary version frequency."
    }
  ],

  "rigidity_points": [
    {
      "area": "Feature Store as single source of truth",
      "reason": "Training-serving skew is the most common and insidious ML system failure. The Feature Store MUST be the single source of feature computation for both training and inference. This is intentionally rigid — no shortcutting feature computation in the serving path."
    },
    {
      "area": "Model versioning and immutability",
      "reason": "Every model artifact must be immutable and versioned. Overwriting a model version is forbidden. This enables rollback and audit. The Model Registry enforces this constraint."
    },
    {
      "area": "P99 latency budget (<100ms)",
      "reason": "This is a hard business constraint (checkout path). Any architectural change that adds latency to the serving path must be evaluated against this budget. This rules out external model servers with network hops, synchronous feature computation, or complex ensemble models."
    }
  ],

  "risks": [
    {
      "risk": "Training-serving skew: features computed differently in training vs inference, leading to silently degraded predictions",
      "severity": "critical",
      "mitigation": "Feature Store as single source of truth. Feature definitions are shared code. CI tests that verify feature parity. Log feature vectors at serving time and compare distributions with training data."
    },
    {
      "risk": "Silent model degradation: new model passes offline eval but performs poorly on live traffic due to distribution shift",
      "severity": "critical",
      "mitigation": "Canary deployment with automatic rollback. Monitor prediction error (MAE) against actuals with a 2-hour delay (delivery completion). Set alerting thresholds. Shadow mode for first deployment."
    },
    {
      "risk": "Feature freshness: stale weather or courier load data in Redis leads to inaccurate predictions",
      "severity": "high",
      "mitigation": "Feature freshness SLA per feature (e.g., weather: 15min, courier load: 1min). Monitor freshness. Prediction API returns a confidence_interval that widens when features are stale. Alert when freshness SLA is breached."
    },
    {
      "risk": "Redis failure takes down predictions (single point of failure on the hot path)",
      "severity": "high",
      "mitigation": "Redis Sentinel or Cluster for HA. Fallback: if Redis is unavailable, serve predictions using default/average feature values with a wider confidence interval and a degraded flag. Never block checkout."
    },
    {
      "risk": "Team of 4 stretched too thin across ML and platform concerns",
      "severity": "medium",
      "mitigation": "Clear ownership split: 2 ML engineers own Training Pipeline + Feature Engineering + model quality. 2 platform engineers own Prediction API + Feature Store infra + Deployment Controller + monitoring. Minimize custom tooling — use managed services where ROI is clear (e.g., managed Redis, S3, scheduled compute)."
    },
    {
      "risk": "Feedback loop delay: actual delivery times arrive hours after prediction, making real-time monitoring of model quality difficult",
      "severity": "medium",
      "mitigation": "Monitor proxy metrics in real-time (prediction distribution stability, latency, feature freshness). Use actual outcome metrics with a lag for model quality assessment. Set the canary window to 24-48 hours to accumulate enough actuals before promotion."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (Weeks 1-3): Prediction API + in-process model + Redis feature store + basic model registry (S3 + metadata table). Ship a heuristic model (distance/speed lookup) first to validate the serving path end-to-end under the 100ms constraint. Phase 2 (Weeks 4-6): Training Pipeline + Delivery Outcome Collector + offline feature store. Train the first real model. Manual deployment via CLI. Phase 3 (Weeks 7-8): Deployment Controller with canary + auto-rollback. Monitoring dashboards. Phase 4 (ongoing): Iterate on features, model quality, and automation.",
    "files_to_create_or_modify": [
      "services/prediction-api/ — FastAPI or Flask service with model loading, feature fetching, inference endpoint",
      "services/prediction-api/model_loader.py — Loads model from S3/local, supports hot-reload on version change",
      "services/prediction-api/feature_client.py — Redis client for online feature reads, with fallback defaults",
      "pipelines/training/ — Training pipeline: data extraction, feature join, model training, evaluation, registry upload",
      "pipelines/features/ — Feature computation jobs (batch for offline store, streaming/cron for online store)",
      "infra/model-registry/ — S3 bucket config + PostgreSQL schema for model metadata and deployment state",
      "tools/deploy-model/ — CLI tool for Deployment Controller: promote, rollback, canary status",
      "monitoring/ — Dashboards and alert definitions for latency, prediction quality, feature freshness"
    ],
    "patterns_to_follow": "Use Python throughout for ML/platform consistency with a 4-person team. FastAPI for the Prediction API (async, fast, good for ML serving). LightGBM for the model (fast training, fast inference, excellent on tabular data). Redis for online features. S3 + PostgreSQL for model registry. Airflow or a simple cron for the weekly training pipeline — do NOT introduce Kubeflow or similar for a team of 4. Feature definitions as shared Python modules imported by both training and serving code.",
    "pitfalls_to_avoid": [
      "DO NOT compute features inline during inference — always read pre-computed features from the store",
      "DO NOT overwrite model artifacts — every version is immutable, rollback depends on this",
      "DO NOT skip canary deployment, even under time pressure — a bad model in checkout is a revenue event",
      "DO NOT use a separate feature definition for training vs serving — this is the #1 cause of ML system failures",
      "DO NOT introduce Kubernetes, Kubeflow, or heavy ML platforms — the team of 4 will spend all their time on infra instead of model quality",
      "DO NOT add GPU infrastructure unless the model provably needs it — tree models do not",
      "DO NOT block the checkout flow if the prediction service is unhealthy — return a fallback estimate with a wider confidence interval"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Serving architecture — in-process LightGBM behind FastAPI will meet 100ms P99 easily",
      "Model registry with immutable versioning and rollback — well-established pattern",
      "Feature store design — Redis online + warehouse offline is the standard approach at this scale",
      "Team sizing — the ownership split (2 ML + 2 platform) maps cleanly to the component boundaries"
    ],
    "low_confidence_areas": [
      "Exact canary promotion criteria — depends on delivery volume and how quickly actuals arrive; may need tuning",
      "Feature freshness requirements for weather and courier load — depends on data provider SLAs not specified",
      "Whether the existing checkout service can tolerate an additional synchronous dependency — needs validation"
    ],
    "assumptions": [
      "The feature set is primarily tabular (no images, no free text) — tree models are the right choice",
      "Prediction volume is moderate (thousands to low millions per day) — single Redis instance or small cluster suffices",
      "The team has Python ML experience (LightGBM, scikit-learn ecosystem)",
      "Infrastructure exists for running scheduled batch jobs (ECS, Cloud Run, or equivalent)",
      "The checkout service already has a mechanism for calling downstream services with timeout budgets"
    ]
  }
}
